member.summary:
Static helpers shared by all built-in SDK actions.
Provides safe argument parsing and faction access so individual actions
stay short and focus on their own logic.

Usage pattern for a new IModTextAction:

public bool Execute(string[] args, GameCommandsReadyEvent? ctx)
{
    if (!ActionContextHelper.TryGetFloat(args, 0, out float amount, _log, CommandName))
        return false;
    if (!ActionContextHelper.TryGetFaction(ctx, out var faction, _log, CommandName))
        return false;

    faction.AddResearchPoints(amount);
    return true;
}

example.code:
if (!ActionContextHelper.TryGetFaction(ctx, out var faction, _log, CommandName))
    return false;
faction.AddResearchPoints(500f);

public class SpawnMyUnit : IModTextAction
{
    public string CommandName => "SpawnMyUnit";

    public bool Execute(string[] args, GameCommandsReadyEvent ctx)
    {
        string unitId = args.Length > 0 ? args[0] : "default_unit";
        // use ctx.NativeUniverse, ctx.NativePlayerFaction, etc.
        Log.LogInfo($"Spawning unit {unitId}");
        return true;
    }
}

// In plugin Load():
ModTextActionRegistry.Register<SpawnMyUnit>();

// In YAML:
actions:
  - command: SpawnMyUnit
    arguments:
      - my_unit_id

// Register by type (instance created automatically):
ModTextActionRegistry.Register<SpawnMyUnit>();

// Register an existing instance:
ModTextActionRegistry.Register(new SpawnMyUnit());

// Check registration:
bool ok = ModTextActionRegistry.IsRegistered("SpawnMyUnit");

// List all actions:
foreach (var name in ModTextActionRegistry.RegisteredActions)
    Log.LogInfo(name);

// Start dialogue between player faction and scientist
var result = new StartDialogueCommand(playerFaction, scientist, DialogueType.Research).Execute();

// Using convenience method
var result = Commands.StartDialogue(playerFaction, scientist, DialogueType.Research);

// Chain dialogues in a faction builder
Commands.ForFaction(playerFaction)
    .StartDialogue(scientist, DialogueType.Introduction)
    .StartDialogue(engineer, DialogueType.ProjectUpdate)
    .Execute();

// Research advanced engineering for player faction
var result = new ResearchTechnologyCommand(playerFaction, TechnologyType.AdvancedEngineering).Execute();

// Using convenience method
var result = Commands.ResearchTechnology(playerFaction, TechnologyType.AdvancedEngineering);

// Chain multiple technology research
Commands.ForFaction(playerFaction)
    .ResearchTechnology(TechnologyType.BasicEngineering)
    .ResearchTechnology(TechnologyType.AdvancedEngineering)
    .ResearchTechnology(TechnologyType.ExpertEngineering)
    .Execute();

// Unlock basic chemistry knowledge for player faction
var result = new UnlockKnowledgeCommand(playerFaction, KnowledgeType.BasicChemistry).Execute();

// Using convenience method
var result = Commands.UnlockKnowledge(playerFaction, KnowledgeType.BasicChemistry);

// Unlock multiple knowledge items in sequence
Commands.ForFaction(playerFaction)
    .UnlockKnowledge(KnowledgeType.BasicPhysics)
    .UnlockKnowledge(KnowledgeType.BasicChemistry)
    .UnlockKnowledge(KnowledgeType.BasicBiology)
    .Execute();

// Lock advanced physics knowledge from AI faction
var result = new LockKnowledgeCommand(aiFaction, KnowledgeType.AdvancedPhysics).Execute();

// Lock multiple knowledge items for a faction
Commands.ForFaction(restrictedFaction)
    .LockKnowledge(KnowledgeType.NuclearPhysics)
    .LockKnowledge(KnowledgeType.QuantumMechanics)
    .Execute();

var actions = YamlCommandsParser.ParseFile("startup-actions.yaml");
int executed = YamlCommandsExecutor.ExecuteActions(actions);
Log.Info($"Executed {executed} / {actions.Count} actions");

// Parse from raw YAML string
var actions = YamlCommandsParser.ParseString(@"
  - command: FinishConstructions
    arguments: []
    daysDelay: 0.0
    showInFrontend: false
");

// Parse from a dedicated actions file
var actions = YamlCommandsParser.ParseFile(@"C:\mods\my-mod\startup-actions.yaml");
